---@type LGpBaseMgr
local LGpBaseMgr = LxRequire("LApp.gameplay.Base.LGpBaseMgr")
---@class LNewbieManager: LGpBaseMgr
local LNewbieManager = LxClass("LNewbieManager", LGpBaseMgr)

LXImport(".LNewbieConst")

local LFightIdleEffectCtrl = LXImport("LApp.gameplay.fightIdle.Ctrl.LFightIdleEffectCtrl")
local LNewbieEventCtrl = LXImport(".Ctrl.LNewbieEventCtrl")


function LNewbieManager:LNewbieManager()
    ---@type LNewbieEventCtrl
    self._eventCtrl = nil
end

function LNewbieManager:Create()
    return LGpBaseMgr.Create(self)
end

function LNewbieManager:InitStart()
    LGpBaseMgr.InitStart(self)
    return true
end

function LNewbieManager:StartNewbie(storyId, isJustShowUI, endCall)
    local cfg = gModelPlot:GetStoryNewbieRef(storyId)
    if not cfg then
        printErrorN("not StoryNewbie cfg id "..storyId)
        return
    end

    self:Clear()

    self._isJustShowUI = isJustShowUI
    self._endCall = endCall

    self._isRunning = true
    gModelGeneral:SetInStory(true)
    self._storyId = storyId
    self:SetUIVisible(false)

    self:InitCtrl()

    self:InitTouchEvent()

    self._eventCtrl:InitStoryEvent(self._storyId)

    if isJustShowUI then
        self._isMapLoaded = true
    end
    if not self._isMapLoaded then
        GF.ChangeMap("LNewbieMap")
    end

    self._isWndReady = false
    local wnd = GF.FindFirstWndByName("UINeie")
    if not wnd then
        GF.OpenWnd("UINeie",{operType = 0})
    else
        self._isWndReady = wnd:IsWndValid()
        self:RunNewbie()
    end
end

function LNewbieManager:OnWndLoaded()
    self._isWndReady = true
    self:RunNewbie()
end

function LNewbieManager:OnMapLoaded(mapTrans, cameraGo)
    gModelGeneral:SetInStory(true)
    self._mapTrans = mapTrans
    self._cameraGo = cameraGo
    self:InitRootNode()
    self._isMapLoaded = true

    self:RunNewbie()
end

function LNewbieManager:RunNewbie()
    if not self._isMapLoaded then return end
    if not self._isInit then return end
    if not self._isWndReady then return end
    self:StartIdleRun()
end

function LNewbieManager:InitRootNode()
    local mapTrans = self._mapTrans

    local layerRoot = CS.FindTrans(mapTrans,"LayerRoot")
    self._layerRootTrans = layerRoot

    local layerTrans
    layerTrans = CS.FindTrans(layerRoot,"LayerObject")
    if not layerTrans then
        layerTrans = CS.NewObject("LayerObject",layerRoot)
    end
    self._objRootTrans = layerTrans

    layerTrans = CS.FindTrans(layerRoot,"LayerEffect")
    if not layerTrans then
        layerTrans = CS.NewObject("LayerEffect",layerRoot)
    end
    self._effectRootTrans = layerTrans
end


function LNewbieManager:StartIdleRun()
    self:StopIdleRun()
    self._loopTimer = LxTimer.LoopTimeCall(function()
        self:OnIdleRun()
    end,0,false,-1)
end

function LNewbieManager:StopIdleRun()
    if not self._loopTimer  then return end
    LxTimer.LoopTimeStop(self._loopTimer)
    self._loopTimer  = nil
end

function LNewbieManager:OnIdleRun()
    if self._waitFinished then
        self._waitFinished = nil
        self:OnNewbieFinished()
        return
    end
    local time = self:GetTime()
    self._effCtrl:OnRun(time)
    self._eventCtrl:OnRun(time)

    if self._eventCtrl:IsFinished() then
        self._waitFinished = true
    end
end

function LNewbieManager:IsCanRecord()
    return not self._isJustShowUI
end
function LNewbieManager:OnNewbieFinished()
    if self._isJustShowUI then
        local endCall = self._endCall
        self:StopStory()
        self:SetUIVisible(true)
        self:Clear()
        if endCall ~= nil then
            endCall()
        end
        return
    end
    gModelPlot:OnSceneSystemLookReq(0, ModelPlot.START_TYPE_2)
    self:StopStory()
    self:SetUIVisible(true, 0.5)
    local battleNode = tonumber(gModelPlot:GetPara("storynovicecombat"))
    if battleNode and battleNode > 0 then
        if not gModelInstance:IsBattleNodePass(battleNode) then
            FireEvent(EventNames.ONLY_CHANGE_MAIN_BTN_ON, {index=LMainBtnIndexConst.ADVENTURE})
            gModelBattle:FirstGotoMainBattle()
            return
        end
    end
    GF.ChangeMap("LCityMap")
end


function LNewbieManager:GetTime()
    if self._time then
        return self._time
    else
        return Time.time+ (self._timeDif or 0)
    end
end

function LNewbieManager:InitCtrl()
    self._effCtrl = LFightIdleEffectCtrl:New(self)
    self._eventCtrl = LNewbieEventCtrl:New(self)

    self._isInit = true
end

function LNewbieManager:GetStoryId()
	if self._eventCtrl then
		return self._eventCtrl:GetStoryId()
	else
		return 0
	end
end

function LNewbieManager:GetEffCtrl()
    return self._effCtrl
end

function LNewbieManager:GetEffectRootTrans()
    return self._effectRootTrans
end


---@return LNewbieEventCtrl
function LNewbieManager:GetEventCtrl()
    return self._eventCtrl
end

function LNewbieManager:NotifyHeroLoaded(heroId)
   self._eventCtrl:NotifyHeroLoaded(heroId)
end

function LNewbieManager:SetUIVisible(isVisible, time)
    FireEvent(EventNames.ON_STORY_SHOW_WND,"story",isVisible, time)
end

function LNewbieManager:StopStory()
    self:StopIdleRun()
    self:RemoveTouchEvent()

    self._isRunning = false

    gModelGeneral:SetInStory(false)
end

function LNewbieManager:IsStoryStop()
    return not self._isRunning
end

function LNewbieManager:IsRunning()
    return self._isRunning
end

function LNewbieManager:Destroy()
    self:Clear()
    self:SetUIVisible(true)
    self:RemoveTouchEvent()
    LGpBaseMgr.Destroy(self)
end


function LNewbieManager:EnableSound()
    return true
end

function LNewbieManager:Clear()
    self:StopIdleRun()
    self:RemoveTouchEvent()

    self._isJustShowUI = nil
    self._endCall = nil

    if self._eventCtrl then
        self._eventCtrl:Destroy()
        self._eventCtrl = nil
    end

    if(self._effCtrl) then
        self._effCtrl:Destroy()
        self._effCtrl = nil
    end

    GF.CloseWndByName("UINeie")
    self._isInit = false
    self._isRunning = false
end

